import React, { useState, useEffect } from 'react';

function AvatarPreview({ user, measurements, outfit, onBack }) {
  const [svgContent, setSvgContent] = useState('');
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const response = await fetch(`http://localhost:3000/api/users/${user.id}/profile`);
      const data = await response.json();
      setProfile(data);
      generateAvatar(data, measurements);
    } catch (error) {
      console.error('Error fetching profile:', error);
      generateAvatar(null, measurements);
    } finally {
      setLoading(false);
    }
  };

  const getSkinTone = (tone) => {
    const tones = {
      'Fair': '#f5d5b8',
      'Light': '#e8c5a5',
      'Medium': '#d4956e',
      'Tan': '#bf8f5f',
      'Deep': '#8b6f47',
    };
    return tones[tone] || '#d4956e';
  };

  const generateAvatar = (profileData, meas) => {
    const skinTone = getSkinTone(profileData?.profile?.skinTone || 'Medium');
    const bodyType = profileData?.profile?.bodyType || 'Average';
    const chest = meas?.chest || 36;

    // Calculate scale based on measurements
    let scale = chest / 36;
    if (bodyType === 'Petite') scale *= 0.85;
    if (bodyType === 'Plus-size') scale *= 1.2;
    if (bodyType === 'Tall') scale *= 1.1;

    const svg = `<svg width="100%" height="100%" viewBox="0 0 300 500" xmlns="http://www.w3.org/2000/svg">
      <defs>
        <linearGradient id="skin" x1="0" y1="0" x2="100" y2="0">
          <stop offset="0%" style="stop-color:${skinTone};stop-opacity:1" />
          <stop offset="100%" style="stop-color:#${adjustBrightness(skinTone, -20)};stop-opacity:0.95" />
        </linearGradient>
        <radialGradient id="faceShadow" cx="40%" cy="40%">
          <stop offset="0%" style="stop-color:#fff;stop-opacity:0.3" />
          <stop offset="100%" style="stop-color:#000;stop-opacity:0.1" />
        </radialGradient>
      </defs>

      <!-- Background -->
      <rect width="300" height="500" fill="#fafafa"/>

      <!-- Shadow -->
      <ellipse cx="150" cy="480" rx="60" ry="12" fill="#00000015"/>

      <!-- BODY/TORSO -->
      <path d="M 110 ${140 * scale} 
               C 95 ${160 * scale}, 85 ${220 * scale}, 90 ${320 * scale}
               L 90 ${420 * scale}
               L 210 ${420 * scale}
               L 210 ${320 * scale}
               C 215 ${220 * scale}, 205 ${160 * scale}, 190 ${140 * scale}
               Z" 
            fill="${skinTone}"/>

      <!-- NECK -->
      <rect x="130" y="${120 * scale}" width="40" height="${30 * scale}" fill="${skinTone}"/>

      <!-- HEAD -->
      <ellipse cx="150" cy="${80 * scale}" rx="50" ry="60" fill="${skinTone}"/>
      <ellipse cx="150" cy="${80 * scale}" rx="50" ry="60" fill="url(#faceShadow)"/>

      <!-- HAIR (darker, more realistic) -->
      <ellipse cx="150" cy="${50 * scale}" rx="52" ry="40" fill="#3d2817"/>
      <path d="M 100 ${70 * scale} Q 100 ${20 * scale}, 150 ${10 * scale} Q 200 ${20 * scale}, 200 ${70 * scale}" fill="#3d2817"/>
      <path d="M 100 ${75 * scale} Q 102 ${35 * scale}, 150 ${25 * scale} Q 198 ${35 * scale}, 200 ${75 * scale}" fill="#5a4a3a" opacity="0.4"/>

      <!-- EYES -->
      <!-- Eye whites -->
      <ellipse cx="130" cy="${75 * scale}" rx="9" ry="12" fill="#fff" stroke="#e0e0e0" stroke-width="0.5"/>
      <ellipse cx="170" cy="${75 * scale}" rx="9" ry="12" fill="#fff" stroke="#e0e0e0" stroke-width="0.5"/>

      <!-- Iris -->
      <circle cx="132" cy="${77 * scale}" r="6" fill="#8b6f47"/>
      <circle cx="172" cy="${77 * scale}" r="6" fill="#8b6f47"/>

      <!-- Pupil -->
      <circle cx="132" cy="${77 * scale}" r="3.5" fill="#000"/>
      <circle cx="172" cy="${77 * scale}" r="3.5" fill="#000"/>

      <!-- Eye shine -->
      <circle cx="133" cy="${75 * scale}" r="1.5" fill="#fff"/>
      <circle cx="173" cy="${75 * scale}" r="1.5" fill="#fff"/>

      <!-- EYEBROWS -->
      <path d="M 118 ${65 * scale} Q 130 ${60 * scale} 142 ${64 * scale}" stroke="#3d2817" stroke-width="2.5" fill="none" stroke-linecap="round"/>
      <path d="M 158 ${64 * scale} Q 170 ${60 * scale} 182 ${65 * scale}" stroke="#3d2817" stroke-width="2.5" fill="none" stroke-linecap="round"/>

      <!-- NOSE -->
      <path d="M 150 ${75 * scale} L 150 ${95 * scale}" stroke="#${adjustBrightness(skinTone, -25)}" stroke-width="1.5" fill="none" opacity="0.6"/>
      <ellipse cx="145" cy="${97 * scale}" rx="3" ry="2.5" fill="#${adjustBrightness(skinTone, -25)}" opacity="0.4"/>
      <ellipse cx="155" cy="${97 * scale}" rx="3" ry="2.5" fill="#${adjustBrightness(skinTone, -25)}" opacity="0.4"/>

      <!-- MOUTH -->
      <path d="M 135 ${105 * scale} Q 150 ${112 * scale} 165 ${105 * scale}" stroke="#d4746d" stroke-width="2" fill="none" stroke-linecap="round"/>
      <path d="M 135 ${105 * scale} Q 150 ${110 * scale} 165 ${105 * scale}" stroke="#e8a5a0" stroke-width="1" fill="none" opacity="0.6"/>

      <!-- EARS -->
      <ellipse cx="102" cy="${80 * scale}" rx="10" ry="22" fill="${skinTone}" stroke="#${adjustBrightness(skinTone, -15)}" stroke-width="0.5"/>
      <ellipse cx="198" cy="${80 * scale}" rx="10" ry="22" fill="${skinTone}" stroke="#${adjustBrightness(skinTone, -15)}" stroke-width="0.5"/>
      <ellipse cx="104" cy="${82 * scale}" rx="5" ry="12" fill="#${adjustBrightness(skinTone, -20)}"/>
      <ellipse cx="196" cy="${82 * scale}" rx="5" ry="12" fill="#${adjustBrightness(skinTone, -20)}"/>

      <!-- LEFT ARM -->
      <ellipse cx="75" cy="${180 * scale}" rx="16" ry="60" fill="${skinTone}" transform="rotate(-25 75 ${180 * scale})"/>

      <!-- RIGHT ARM -->
      <ellipse cx="225" cy="${180 * scale}" rx="16" ry="60" fill="${skinTone}" transform="rotate(25 225 ${180 * scale})"/>

      <!-- HANDS -->
      <ellipse cx="55" cy="${280 * scale}" rx="13" ry="18" fill="${skinTone}" transform="rotate(-25 55 ${280 * scale})"/>
      <ellipse cx="245" cy="${280 * scale}" rx="13" ry="18" fill="${skinTone}" transform="rotate(25 245 ${280 * scale})"/>

      <!-- SHIRT/CLOTHING -->
      <path d="M 110 ${140 * scale}
               L 95 ${160 * scale}
               L 95 ${320 * scale}
               L 205 ${320 * scale}
               L 205 ${160 * scale}
               L 190 ${140 * scale}
               Z"
            fill="#8B4789" stroke="#6B2F69" stroke-width="1"/>

      <!-- Shirt highlight/shading -->
      <ellipse cx="130" cy="${200 * scale}" rx="25" ry="50" fill="#fff" opacity="0.12"/>
      <path d="M 110 ${140 * scale} L 190 ${140 * scale}" stroke="#fff" stroke-width="1" opacity="0.3"/>

      <!-- PANTS -->
      <rect x="95" y="${320 * scale}" width="40" height="100" fill="#1a1a1a"/>
      <rect x="165" y="${320 * scale}" width="40" height="100" fill="#0d0d0d"/>

      <!-- SHOES -->
      <ellipse cx="115" cy="${425 * scale}" rx="18" ry="14" fill="#000"/>
      <ellipse cx="185" cy="${425 * scale}" rx="18" ry="14" fill="#000"/>
      <ellipse cx="115" cy="${422 * scale}" rx="15" ry="8" fill="#1a1a1a"/>
      <ellipse cx="185" cy="${422 * scale}" rx="15" ry="8" fill="#1a1a1a"/>
    </svg>`;

    setSvgContent(svg);
  };

  const adjustBrightness = (hex, percent) => {
    const num = parseInt(hex.replace("#", ""), 16);
    const amt = Math.round(2.55 * percent);
    const R = Math.min(255, (num >> 16) + amt);
    const G = Math.min(255, (num >> 8 & 0x00) + amt);
    const B = Math.min(255, (num & 0x0000FF) + amt);
    return ((0x1000000 + (R << 16) + (G << 8) + B).toString(16).slice(1));
  };

  if (loading) return <div className="App"><div className="card"><p>Loading...</p></div></div>;

  return (
    <div className="App avatar-preview">
      <div className="navbar">
        <h1>👤 Your Avatar</h1>
        <button onClick={onBack} className="back-btn">← Back</button>
      </div>
      <div className="avatar-container">
        <div className="avatar-display" dangerouslySetInnerHTML={{ __html: svgContent }} />
        <div className="avatar-info">
          <h2>Your Profile</h2>
          {profile && (
            <div className="info-box">
              <p><strong>Body Type:</strong> {profile.profile?.bodyType || 'Not set'}</p>
              <p><strong>Skin Tone:</strong> {profile.profile?.skinTone || 'Not set'}</p>
              <p><strong>Style:</strong> {profile.profile?.style || 'Not set'}</p>
              <hr style={{margin: '15px 0', border: 'none', borderTop: '1px solid #ddd'}} />
              <p><strong>Chest:</strong> {profile.measurements?.chest || 'Not set'}"</p>
              <p><strong>Waist:</strong> {profile.measurements?.waist || 'Not set'}"</p>
              <p><strong>Hips:</strong> {profile.measurements?.hips || 'Not set'}"</p>
              <p><strong>Height:</strong> {profile.measurements?.height || 'Not set'}'</p>
            </div>
          )}
          <button onClick={onBack} className="btn-primary" style={{width: '100%', marginTop: '20px'}}>← Back</button>
        </div>
      </div>
    </div>
  );
}

export default AvatarPreview;mka
